<template>
    <div class="card mb-0 pt-2 pt-md-0">
        <!--<div class="card-header bg-primary">
            <h6 class="my-0 text-white">Consulta kardex</h6>
        </div> -->
        <div class="card mb-0">
                <div class="card-body">
                    <data-table :resource="resource" :establecimiento.sync="establecimiento" >
                        <tr slot="heading">
                            <th>#</th>
                            <th v-if="!item_id">Producto</th>
                            <th>Fecha y hora transacción</th>
                            <th>Tipo transacción</th>
                                                        <th>Comentario</th>
                            <th>Número</th>

                            <th>NV. Asociada</th>
                            <th>Feha emisión</th>
                            <th>Entrada</th>
                            <th>Salida</th>
                            <th>Saldo</th>

                        </tr>
                        <tr slot-scope="{ index, row }">
                            <td>{{ index }}</td>
                            <td v-if="!item_id">{{row.item_name}}</td>
                            <td>{{row.date_time}}</td>
                            <td>{{row.type_transaction}}</td>
                              <td>{{row.detail}}</td>
                            <td>{{row.number}}</td>
                            <td>{{row.sale_note_asoc}}</td>
                            <td>{{row.date_of_issue}}</td>
                            <td>{{row.input}}</td>
                            <td>{{row.output}}</td>
                            <td>{{row.balance}}</td>
                        </tr>

                    </data-table>


                </div>
        </div>

    </div>
</template>

<script>

    import DataTable from '../../components/DataTableKardex.vue'

    export default {
        props: ["establecimiento"],
        components: {DataTable},
        data() {
            return {
                resource: 'reports/kardex',
                form: {},
                item_id:null
            }
        },
        created() {
            this.$eventHub.$on('emitItemID', (item_id) => {
                // console.log(item_id)
                this.item_id = item_id
            })
        },
        methods: {


        }
    }
</script>



